#### 職人③：宇宙図書館員 (`Format Library Photo`)

*   **役割:** `Fetch Image Library`係が持ち帰った、キーワード検索結果のリストを受け取る。その中から最初の1枚を選び、これもまた「宝石」に加工する。
*   **確認する場所:** `Fetch Image Library`ノードの**すぐ後ろ**にある`Code`ノード。

**【このノードに書かれているべき、唯一無二の正しいコード】**
```javascript
// 図書館係が持ち帰った検索結果を受け取る
const items = $input.all();

// 検索結果（collection.items）が空っぽなら、仕事をおしまいにする
if (!items[0].json.collection || !items[0].json.collection.items || items[0].json.collection.items.length === 0) {
  return [];
}
const libraryItems = items[0].json.collection.items;

// 最初の検索結果を選ぶ
const firstItem = libraryItems[0];

// 説明文が長すぎることがあるので、200文字で切り詰める
const description = firstItem.data[0].description;
const shortDescription = description.length > 200 ? description.substring(0, 200) + '...' : description;

// 「統一規格」に従って、箱詰めする
const finalPart = {
  source: "Image Library",
  title: `宇宙の神秘：${firstItem.data[0].title}`,
  url: firstItem.links[0].href,
  explanation: shortDescription
};

// 完成部品を次の工程へ渡す
return [{ json: finalPart }];

// 図書館係が持ち帰った検索結果を受け取る
const items = $input.all();

// 検索結果（collection.items）が空っぽなら、仕事をおしまいにする
if (!items[0].json.collection || !items[0].json.collection.items || items[0].json.collection.items.length === 0) {
  return [];
}
const libraryItems = items[0].json.collection.items;

// 最初の検索結果を選ぶ
const firstItem = libraryItems[0];

// 説明文が長すぎることがあるので、200文字で切り詰める
const description = firstItem.data[0].description;
const shortDescription = description.length > 200 ? description.substring(0, 200) + '...' : description;

// 「統一規格」に従って、箱詰めする
const finalPart = {
  source: "Image Library",
  title: `宇宙の神秘：${firstItem.data[0].title}`,
  url: firstItem.links[0].href,
  explanation: shortDescription
};

// 完成部品を次の工程へ渡す
return [{ json: finalPart }];

// EPIC係が持ち帰ったカタログを受け取る
const items = $input.all();

// カタログが空っぽなら、静かに仕事をおしまいにする
if (items.length === 0 || !items[0].json || items[0].json.length === 0) {
  return []; 
}
const epicImages = items[0].json;

// 最新の（リストの最初の）写真を選ぶ
const latestImage = epicImages[0];

// 秘伝の技で、URLを組み立てる
const dateStr = latestImage.date;
const [year, month, day] = dateStr.split(' ')[0].split('-');
const imageName = latestImage.image;
const imageUrl = `https://epic.gsfc.nasa.gov/archive/natural/${year}/${month}/${day}/png/${imageName}.png`;

// 「統一規格」に従って、箱詰めする
const finalPart = {
  source: "EPIC",
  title: `故郷、地球の肖像 (${latestImage.date})`,
  url: imageUrl,
  explanation: latestImage.caption || '我々の故郷、地球の美しい姿。'
};

// 完成部品を次の工程へ渡す
return [{ json: finalPart }];

// AIによって魂を吹き込まれた、3つの完成部品を受け取る
// この時点では、入力データは3つのアイテムになっているはずじゃ
const finalParts = $input.all();

// --- ここから、Slackメッセージという名の芸術品を創り上げる ---

let finalMessage = "🌌 **本日の宇宙セレクション** 🌌\n\n";
finalMessage += "地球、火星、そして深宇宙から届いた、魂のキャプション付きセレクションです！\n";
finalMessage += "---------------------------------\n\n";

// forEachという魔法の呪文で、3つの部品を一つずつ処理していく
finalParts.forEach(part => {
  // 元の写真情報を取り出す
  const photoInfo = part.json;

  // AIが生成した、魂のキャプションを取り出す
  // AI Agentノードは 'output' という名前で結果を返す
  const aiCaption = photoInfo.output;

  finalMessage += `*📸 from ${photoInfo.source}: ${photoInfo.title}*\n`;
  // ここで、無機質な説明文の代わりに、AIのキャプションを使う！
  finalMessage += `> ${aiCaption}\n`;
  finalMessage += `${photoInfo.url}\n\n`;
});

finalMessage += "---------------------------------\n";
finalMessage += "お気に入りの一枚にリアクションで教えておくれ！ (地球: 🌎, 火星: 🔥, 宇宙: ✨)";

// 完成したメッセージを、Slack報告係に渡すための箱に入れる
return [{ json: { slackMessage: finalMessage } }];
